SELECT dt.id, 1, true, '{"version": "1.0", "fields": [{"id": "project_name", "type": "text", "label": "案件名", "required": true}, {"id": "customer_name", "type": "text", "label": "顧客名", "required": true}, {"id": "request_content", "type": "textarea", "label": "依頼内容", "required": true, "rows": 6}, {"id": "deadline", "type": "date", "label": "納期", "required": true}, {"id": "budget", "type": "currency", "label": "予算", "required": false}, {"id": "remarks", "type": "textarea", "label": "備考", "required": false, "rows": 3}], "layout": {"type": "sections", "sections": [{"title": "基本情報", "fields": ["project_name", "customer_name"]}, {"title": "依頼詳細", "fields": ["request_content", "deadline", "budget"]}, {"title": "備考", "fields": ["remarks"]}]}}'::jsonb
FROM document_types dt WHERE dt.code = 'T01';

