-- ============================================
-- 7. Insert approval route templates and steps
-- ============================================

-- Route: デザイン企画依頼書 承認ルート
INSERT INTO approval_route_templates (document_type_id, name, is_default, is_active)
SELECT dt.id, 'デザイン企画依頼書 承認ルート', true, true
FROM document_types dt WHERE dt.code = 'T01';

INSERT INTO approval_route_steps (route_template_id, step_order, name, assignee_type, assignee_position_id)
SELECT art.id, 1, '営業課長', 'position_in_department', p.id
FROM approval_route_templates art
JOIN document_types dt ON art.document_type_id = dt.id
CROSS JOIN positions p
WHERE dt.code = 'T01' AND art.name = 'デザイン企画依頼書 承認ルート' AND p.code = 'KACHO';

INSERT INTO approval_route_steps (route_template_id, step_order, name, assignee_type, assignee_position_id)
SELECT art.id, 2, '営業部長', 'position_in_parent_department', p.id
FROM approval_route_templates art
